        {/* Input Bar - Hidden on Print */}
        <div className="bg-white rounded-lg shadow-sm border border-slate-200 p-6 mb-8 no-print">
            <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
