// --- App Content Component ---
const AppContent: React.FC = () => {
    const { t } = useTranslations();
    const [view, setView] = useState('landing');
    const [showSplash, setShowSplash] = useState(true);
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [scrollY, setScrollY] = useState(0);

    useEffect(() => {
        const handleScroll = () => {
            setScrollY(window.scrollY);
        };
        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    useEffect(() => {
        const rootEl = document.getElementById('root');
        if (rootEl) {
            if (isAuthenticated) {
                rootEl.classList.add('dashboard-view');
            } else {
                rootEl.classList.remove('dashboard-view');
            }
        }
        return () => {
            if (rootEl) {
                rootEl.classList.remove('dashboard-view');
            }
        };
    }, [isAuthenticated]);

    const handleEnterApp = () => setShowSplash(false);
    const handleNavigateToLanding = () => { window.scrollTo(0, 0); setView('landing'); };
    const handleNavigateToLogin = () => { window.scrollTo(0, 0); setView('login'); };
    const handleNavigateToAgreement = () => { window.scrollTo(0, 0); setView('consultant-agreement'); };
    const handleNavigateToCalendar = () => { window.scrollTo(0, 0); setView('event-calendar'); };
    const handleNavigateToBookRelease = () => { window.scrollTo(0, 0); setView('book-release'); };
    const handleNavigateToMembershipPromo = () => { window.scrollTo(0, 0); setView('membership-promo'); };
    const handleNavigateToContactBooking = () => { window.scrollTo(0, 0); setView('contact-booking'); };
    const handleNavigateToServices = () => { window.scrollTo(0, 0); setView('services'); }; // New handler

    const handleNavigateToApplication = () => {
        setView('landing');
        // Use setTimeout to allow landing page to render before scrolling
        setTimeout(() => {
            const el = document.getElementById('ansokan');
            if (el) {
                const headerOffset = 100;
                const elementPosition = el.getBoundingClientRect().top;
                const offsetPosition = elementPosition + window.scrollY - headerOffset;
                window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
            }
        }, 100);
    };

    const handleLoginSuccess = () => { setIsAuthenticated(true); };
    const handleLogout = () => { setIsAuthenticated(false); setView('landing'); };

    if (showSplash) {
        return <SplashScreen onEnter={handleEnterApp} />;
    }

    if (isAuthenticated) {
        return <BoardMemberPage onLogout={handleLogout} />;
    }

    if (view === 'consultant-agreement') {
        return <ConsultantAgreement onBack={handleNavigateToLanding} />;
    }

    if (view === 'event-calendar') {
        return <EventCalendarView onBack={handleNavigateToLanding} />;
    }

    if (view === 'book-release') {
        return <BookReleasePage onBack={handleNavigateToLanding} />;
    }

    if (view === 'membership-promo') {
        return <MembershipPromo onNavigateToApplication={handleNavigateToApplication} onBack={handleNavigateToLanding} />;
    }

    if (view === 'contact-booking') {
        return <ContactAndBookingPage onBack={handleNavigateToLanding} />;
    }

    if (view === 'services') {
        return <ServicesPage onBack={handleNavigateToLanding} />; // Render Services Page
    }

    return (
      <div className="bg-gray-50/60 dark:bg-slate-900/60 backdrop-blur-lg text-gray-800 dark:text-slate-200 antialiased flex flex-col min-h-screen relative overflow-hidden">
         {/* Blob 1: Cyan/Blue - Top Left */}
         <div 
            className="absolute -top-20 -left-20 w-[600px] h-[600px]"
            style={{ transform: `translateY(${scrollY * 0.4}px)` }}
            >
