                src="https://images.unsplash.com/photo-1521737604893-d14cc237f11d?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&crop=focalpoint&fp-y=.8&w=2830&h=1500&q=80"
                alt=""
                className="absolute inset-0 -z-10 h-full w-full object-cover object-right md:object-center opacity-20"
            />
            <div className="hidden sm:absolute sm:-top-10 sm:right-1/2 sm:-z-10 sm:mr-10 sm:block sm:transform-gpu sm:blur-3xl" aria-hidden="true">
              <div className="aspect-[1097/845] w-[68.5625rem] bg-gradient-to-tr from-[#ff4694] to-[#776fff] opacity-20" style={{ clipPath: 'polygon(74.1% 44.1%, 100% 61.6%, 97.5% 26.9%, 85.5% 0.1%, 80.7% 2%, 72.5% 32.5%, 60.2% 62.4%, 52.4% 68.1%, 47.5% 58.3%, 45.2% 34.5%, 27.5% 76.7%, 0.1% 64.9%, 17.9% 100%, 27.6% 76.8%, 76.1% 97.7%, 74.1% 44.1%)' }} />
            </div>
            <div className="absolute -top-52 left-1/2 -z-10 -translate-x-1/2 transform-gpu blur-3xl sm:top-[-28rem] sm:ml-16 sm:translate-x-0 sm:transform-gpu" aria-hidden="true">
              <div className="aspect-[1097/845] w-[68.5625rem] bg-gradient-to-tr from-[#ff4694] to-[#776fff] opacity-20" style={{ clipPath: 'polygon(74.1% 44.1%, 100% 61.6%, 97.5% 26.9%, 85.5% 0.1%, 80.7% 2%, 72.5% 32.5%, 60.2% 62.4%, 52.4% 68.1%, 47.5% 58.3%, 45.2% 34.5%, 27.5% 76.7%, 0.1% 64.9%, 17.9% 100%, 27.6% 76.8%, 76.1% 97.7%, 74.1% 44.1%)' }} />
            </div>
            <div className="mx-auto max-w-7xl px-6 lg:px-8">
              <div className="mx-auto max-w-2xl text-center">
                <h1 className="text-4xl font-bold tracking-tight text-white sm:text-6xl">{t.appName}</h1>
                <p className="mt-6 text-lg leading-8 text-gray-300">{t.heroSubtitle}</p>
                <div className="mt-10 flex items-center justify-center gap-x-6">
                  <CTAButton href="#ansokan" onClick={(e) => scrollToId(e, 'ansokan')}>{t.becomeMemberToday}</CTAButton>
                </div>
              </div>
            </div>
          </div>

          <div id="varfor-oss" className="scroll-mt-28 py-20 sm:py-28">
            <div className="mx-auto max-w-7xl px-6 lg:px-8">
              <div className="mx-auto max-w-2xl lg:text-center">
                <h2 className="text-base font-semibold leading-7 text-cyan-600 dark:text-cyan-400">{t.ourPromise}</h2>
                <p className="mt-2 text-3xl font-bold tracking-tight text-gray-900 dark:text-white sm:text-4xl">{t.everythingYouNeedToGrow}</p>
                <p className="mt-6 text-lg leading-8 text-gray-600 dark:text-gray-300">{t.platformDescription}</p>
              </div>
              <div className="mx-auto mt-16 max-w-2xl sm:mt-20 lg:mt-24 lg:max-w-4xl">
                <div className="grid max-w-xl grid-cols-1 gap-x-8 gap-y-10 lg:max-w-none lg:grid-cols-2 lg:gap-y-16">
                  {valueProps.map((prop) => (
                    <ValuePropCard key={prop.title} icon={prop.icon} title={prop.title} description={prop.description} />
                  ))}
                </div>
              </div>

              <div className="mt-24">
                  <h2 className="text-4xl font-extrabold tracking-tight text-gray-900 dark:text-white sm:text-6xl mb-6 flex items-center justify-center gap-4">
                      {t.newsTitle}
                      <span className="relative flex h-4 w-4 sm:h-5 sm:w-5">
                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                        <span className="relative inline-flex rounded-full h-full w-full bg-amber-500"></span>
                      </span>
                  </h2>
                  <p className="text-center text-sm text-gray-500 dark:text-gray-400 mb-8 max-w-2xl mx-auto px-4">
                      {t.newsExplainer}
                  </p>

                  {/* Carousel Container - Liquid Glass */}
                  <div 
                    onClick={handleNewsClick}
                    className="relative isolate overflow-hidden rounded-3xl px-6 py-20 text-center sm:px-16 flex flex-col items-center justify-center min-h-[350px] group cursor-pointer transition-all duration-500
                    bg-white/20 dark:bg-slate-900/30 backdrop-blur-2xl 
                    border border-white/30 dark:border-white/10
                    shadow-[0_8px_32px_0_rgba(31,38,135,0.15)] dark:shadow-[0_8px_32px_0_rgba(0,0,0,0.3)] hover:shadow-[0_8px_32px_0_rgba(31,38,135,0.25)] dark:hover:shadow-[0_8px_32px_0_rgba(0,0,0,0.5)]"
                  >
                      {/* Animated Liquid Blobs */}
                      <div className="absolute -top-24 -left-24 w-96 h-96 bg-amber-400/30 rounded-full mix-blend-multiply filter blur-3xl opacity-70 animate-blob dark:bg-amber-600/20 dark:mix-blend-normal"></div>
                      <div className="absolute top-1/2 right-0 w-96 h-96 bg-orange-300/30 rounded-full mix-blend-multiply filter blur-3xl opacity-70 animate-blob animation-delay-2000 dark:bg-orange-600/20 dark:mix-blend-normal"></div>
                      <div className="absolute -bottom-32 left-1/2 transform -translate-x-1/2 w-96 h-96 bg-yellow-300/30 rounded-full mix-blend-multiply filter blur-3xl opacity-70 animate-blob animation-delay-4000 dark:bg-yellow-600/20 dark:mix-blend-normal"></div>

                      {/* Glossy Reflection Overlay */}
                      <div className="absolute inset-0 bg-gradient-to-br from-white/40 via-transparent to-transparent opacity-60 pointer-events-none rounded-3xl"></div>

                      {/* Navigation Buttons */}
                      <button 
                        onClick={prevNews}
                        className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/30 dark:bg-black/30 hover:bg-white/50 dark:hover:bg-black/50 text-amber-900 dark:text-amber-100 transition-all z-30 opacity-100 duration-300 focus:opacity-100 backdrop-blur-md border border-white/20 shadow-lg group-hover:scale-110 group-hover:bg-white/40 dark:group-hover:bg-black/40"
                        aria-label="Föregående nyhet"
                      >
                          <ChevronLeft size={24} className="group-hover:animate-pulse-subtle" />
                      </button>

                      <button 
                        onClick={nextNews}
                        className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/30 dark:bg-black/30 hover:bg-white/50 dark:hover:bg-black/50 text-amber-900 dark:text-amber-100 transition-all z-30 opacity-100 duration-300 focus:opacity-100 backdrop-blur-md border border-white/20 shadow-lg group-hover:scale-110 group-hover:bg-white/40 dark:group-hover:bg-black/40"
                        aria-label="Nästa nyhet"
                      >
                          <ChevronRight size={24} className="group-hover:animate-pulse-subtle" />
                      </button>

                    <div className="relative z-10 transform transition-transform duration-500 group-hover:scale-105 max-w-5xl mx-auto">
                        <div className="mb-8 inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-amber-100/80 dark:bg-amber-900/40 border border-amber-200 dark:border-amber-700/50 text-amber-800 dark:text-amber-200 text-sm font-semibold shadow-sm backdrop-blur-md">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                            </svg>
                            Aktuellt {currentNewsIndex + 1}/{newsItems.length}
                        </div>

                        {/* Key forces re-render of TypewriterEffect when index changes */}
                        <div key={currentNewsIndex}>
                            <TypewriterEffect wordsByLine={newsItems[currentNewsIndex].words} />
                        </div>
                    </div>

                    {/* "Read More" Call to Action Overlay */}
                    <div className="absolute bottom-12 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all duration-500 transform translate-y-4 group-hover:translate-y-0 z-20">
                        <div className="flex items-center gap-2 px-6 py-2 rounded-full bg-white/90 dark:bg-black/80 text-amber-600 dark:text-amber-400 font-bold shadow-lg border border-amber-200/50 dark:border-amber-800/50 backdrop-blur-sm">
                            <span>Läs mer</span>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 animate-bounce" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M13 7l5 5m0 0l-5 5m5-5H6" />
                            </svg>
                        </div>
                    </div>

                    {/* Pagination Indicators */}
                    <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2">
                        {newsItems.map((_, idx) => (
                            <div 
                                key={idx} 
                                className={`h-1.5 rounded-full transition-all duration-300 ${idx === currentNewsIndex ? 'w-6 bg-amber-500' : 'w-1.5 bg-amber-300/50 dark:bg-amber-700/50'}`}
                            />
                        ))}
                    </div>

                  </div>
                </div>
            </div>
          </div>

          <div id="formaner" className="scroll-mt-28">
            <MemberBenefits />
          </div>

          <div className="py-16 sm:py-24">
            <div className="mx-auto max-w-7xl px-6 lg:px-8">
              <div className="relative isolate overflow-hidden bg-slate-900 px-6 py-16 text-center shadow-2xl rounded-2xl sm:px-16">
                <h2 className="mx-auto max-w-2xl text-3xl font-bold tracking-tight text-white sm:text-4xl">{t.ctaTitle}</h2>
                <p className="mx-auto mt-6 max-w-xl text-lg leading-8 text-gray-300">{t.ctaSubtitle}</p>
                <div className="mt-10 flex items-center justify-center">
                  <CTAButton href="#ansokan" onClick={(e) => scrollToId(e, 'ansokan')}>{t.joinNow}</CTAButton>
                </div>
                <svg viewBox="0 0 1024 1024" className="absolute left-1/2 top-1/2 -z-10 h-[64rem] w-[64rem] -translate-x-1/2 [mask-image:radial-gradient(closest-side,white,transparent)]" aria-hidden="true">
                  <circle cx={512} cy={512} r={512} fill="url(#827591b1-ce8c-4110-b064-7cb85a0b1217)" fillOpacity="0.7" />
                  <defs>
                    <radialGradient id="827591b1-ce8c-4110-b064-7cb85a0b1217">
                      <stop stopColor="#0891b2" />
                      <stop offset={1} stopColor="#0f172a" />
                    </radialGradient>
                  </defs>
                </svg>
              </div>
              <div className="mt-8 bg-white/60 dark:bg-slate-800/60 backdrop-blur-lg border border-white/20 dark:border-slate-700 px-6 py-8 text-center shadow-lg rounded-2xl">
                <p className="text-xl font-semibold text-slate-800 dark:text-slate-100">
                  {t.boardHint}
                </p>
              </div>
            </div>
          </div>

          <div id="nyhetsbrev" className="scroll-mt-28">
            <NewsletterSignup />
          </div>
          <div id="ansokan" className="scroll-mt-28 py-20 sm:py-28 bg-white/40 dark:bg-slate-800/40">
            <ApplicationForm />
          </div>
          <div id="faq" className="scroll-mt-28">
            <FAQ />
          </div>
          <div id="kontakt" className="scroll-mt-28">
            <ContactForm />
          </div>
        </>
    );
};

export default LandingPage;
